    let mut err_msg = ''
    let err_lines = stdin_text.split('\n')
    let mut ei: i64 = 0
    while ei < err_lines.len() {
        let el = err_lines[ei]
        if el.contains('error[') {
            err_msg = el.trim()
            ei = err_lines.len()
