            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
