let _ph_names = _ph[0]
let _ph_values = _ph[1]

fn n6_match_name(value: float) -> string {
    // n6 상수 (절대 오차 < 0.0001)
    let mut i = 0
    while i < len(_n6_names) {
        if abs_f(value - _n6_values[i]) < 0.0001 {
            return _n6_names[i]
        }
        i = i + 1
    }
    // 물리 상수 (상대 오차 < 1%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.01 {
                return _ph_names[j]
            }
        }
        j = j + 1
    }
    ''
}

fn n6_match_grade(value: float) -> string {
    if n6_match_name(value) != '' {
        return 'EXACT'
    }
    // 물리 상수 NEAR (상대 오차 < 5%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.05 {
                return 'NEAR'
            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // 숫자 아닌 토큰 무시
        }
    }
    nums
}

