        try {
            exec('bash', ['-c', hexa_bin2 + ' ' + gap_finder + ' quick >> ' + _shared + '/auto_gap.log 2>&1 && ' + hexa_bin2 + ' ' + gap_finder + ' dfs 2 >> ' + _shared + '/auto_gap.log 2>&1 && ' + hexa_bin2 + ' ' + gap_finder + ' bridge >> ' + _shared + '/auto_gap.log 2>&1 &'])
            discoveries = discoveries + 1
            if exact_names != '' { exact_names = exact_names + ',' }
            exact_names = exact_names + '🔍GAP:quick+dfs+bridge'
        } catch e {}
    }
}

if discoveries > 0 || bt_detected || gap_detected {
    let mut tags = ''
    if bt_detected { tags = tags + ' 🛸돌파:' + bt_domain }
    if gap_detected { tags = tags + ' 🔍GAP' }
    let mut body = ''
    if discoveries > 0 { body = to_string(discoveries) + '건 감지 [' + exact_names + ']' }
    if body == '' && bt_detected {
        if bt_action == 'converge' { body = '연속돌파 감지 → 즉시 실행: hexa breakthrough.hexa --converge' }
        else if bt_action == 'blowup_loop' { body = '성장돌파 감지 → 즉시 실행: hexa breakthrough.hexa --engine auto' }
        else { body = '돌파 감지 → 즉시 실행: hexa blowup.hexa ' + bt_domain + ' 3 --no-graph' }
    }
    if body == '' && gap_detected { body = '갭 탐색 트리거' }

    // prompt 모드: 지시형 출력 (Claude가 바로 실행하도록)
    if mode == 'prompt' && bt_detected {
        let hexa_path = '$HOME/Dev/hexa-lang/target/release/hexa'
        let nexus_path = '$HOME/Dev/nexus'
        let mut cmd = ''
        if bt_action == 'converge' {
            cmd = 'ssh hetzner '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/breakthrough.hexa --converge''
        } else if bt_action == 'blowup_loop' {
            cmd = 'ssh hetzner '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/breakthrough.hexa --engine auto''
        } else {
            cmd = 'ssh hetzner '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/blowup.hexa ' + bt_domain + ' 3 --no-graph --seeds \'$(~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/seed_engine.hexa merge)\'''
        }
        let directive = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + ' — 확인 질문 없이 즉시 Bash로 실행할 것: ' + cmd + '\'}'
        println(directive)
    } else {
        let msg = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + '\'}'
        println(msg)
    }
}

// ─── prompt 모드: 할일 키워드 감지 → todo_display.hexa 호출 ───
if mode == 'prompt' {
    let todo_keywords = ['다음', '플랜', '할일', '할 일', 'todo', '작업목록', '작업 목록', 'next plan', '진행상황', '진행 상황', 'progress']
    let mut todo_found = false
